tasks = {asyncio.create_task(worker(n)) for n in [1, 2, 3]}

done, pending = await asyncio.wait(tasks, return_when=asyncio.FIRST_COMPLETED)
for t in done:
    print(t.result())
# Cancel anything still running
for t in pending:
    t.cancel()

for coro in asyncio.as_completed([worker(3), worker(1), worker(2)]):
    result = await coro
    print(f"Finished: {result}")  # prints in order: 1, 2, 3

def on_done(task):
    if task.cancelled():
        print("Cancelled")
    elif task.exception():
        print(f"Error: {task.exception()}")
    else:
        print(f"Result: {task.result()}")

task = asyncio.create_task(worker(1))
task.add_done_callback(on_done)

try:
    result = await asyncio.wait_for(worker(5), timeout=2.0)
except asyncio.TimeoutError:
    print("Took too long")
